export default {
    name: 'SideCart',
    props: ['cartShow', 'cart', 'total'],
    emits: ['cartClose'],
    data () {
      return {
        href: this.$route.params.href,
        items: require('../items.json')
      }
    },
    computed: {
      cartTotal () {
        if (!Object.keys(this.cart).length) {
          return 0
        } else {
          return this.total * 590
        }
      }
    }
  }
